from flask import Blueprint, request, jsonify
from yourapp.models import User
from yourapp.utils import current_user, db

update_profile = Blueprint('update_profile', __name__)

@update_profile.route('/profile', methods=['PATCH'])
def update():
    data = request.json
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']

    for field in data:
        if field not in allowed_fields:
            return jsonify({'error': f'Invalid field: {field}'}), 400

    user = current_user
    user.email = data.get('email') or user.email
    user.username = data.get('username') or user.username
    user.account_type = data.get('account_type') or user.account_type
    user.credits = data.get('credits', type=int) or user.credits
    user.referral_code = data.get('referral_code') or user.referral_code
    user.verified_status = data.get('verified_status', type=bool) or user.verified_status

    db.session.commit()
    return jsonify({'message': 'Profile updated successfully'}), 200